import { useEffect, useState } from "react";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const [role, setRole] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const storedRole = localStorage.getItem("role");

    // 🔒 Auth guard
    if (!token) {
      window.location.href = "/";
      return;
    }

    // 🔒 Role guard
    if (storedRole !== "company" && storedRole !== "admin") {
      window.location.href = "/hacker";
      return;
    }

    setRole(storedRole);
  }, []);

  // ⏳ Prevent blank render
  if (!role) return null;

  return (
    <div style={{ padding: "40px", color: "#fff", background: "#0b0f14", minHeight: "100vh" }}>
      <h1>🏢 Company Dashboard</h1>
      <p>You are logged in as <b>{role}</b></p>

      <p style={{ marginTop: "20px", color: "#8b949e" }}>
        Bugs assigned to your company will appear here.
      </p>

      <button
        style={{
          marginTop: "30px",
          padding: "10px 20px",
          background: "#ff4d4d",
          border: "none",
          cursor: "pointer",
        }}
        onClick={() => {
          localStorage.clear();
          window.location.href = "/";
        }}
      >
        Logout
      </button>
    </div>
  );
}
